import React, { useState, useRef } from 'react';
import { Store, ShoppingBag, Shirt, Award, MapPin, Sparkles } from 'lucide-react';

const App = () => {
  const [activeTab, setActiveTab] = useState('exterior');
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const cardRef = useRef(null);

  // Gold Gradient Classes
  const goldGradient = "bg-gradient-to-b from-[#BF953F] via-[#FCF6BA] via-[#B38728] via-[#FBF5B7] to-[#AA771C]";
  const goldText = "text-transparent bg-clip-text bg-gradient-to-b from-[#BF953F] via-[#FCF6BA] to-[#AA771C]";

  // 3D Tilt Logic
  const handleMouseMove = (e) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    setMousePos({ x, y });
  };

  const handleMouseLeave = () => {
    setMousePos({ x: 0, y: 0 });
  };

  const LogoComponent = ({ size = "md", interactive = false }) => {
    const scale = size === "sm" ? "scale-50" : size === "lg" ? "scale-125" : "scale-100";

    // Parallax movement for inner elements
    const innerStyle = interactive ? {
      transform: `translateX(${mousePos.x * 20}px) translateY(${mousePos.y * 20}px)`,
      transition: 'transform 0.1s ease-out'
    } : {};

    return (
      <div className={`flex flex-col items-center ${scale} transition-transform duration-500`}>
        {/* Outer Ring with Real Gold Gradient */}
        <div 
          className="w-32 h-32 rounded-full p-[3px] shadow-[0_0_30px_rgba(191,149,63,0.3)]"
          style={{ background: 'linear-gradient(135deg, #BF953F 0%, #FCF6BA 45%, #B38728 50%, #FBF5B7 55%, #AA771C 100%)' }}
        >
          <div className="w-full h-full rounded-full bg-[#121212] flex items-center justify-center relative overflow-hidden">
             {/* Decorative inner lines */}
             <div className="absolute inset-2 rounded-full border border-[#BF953F]/20"></div>

             {/* Intertwined Monogram with Parallax */}
             <div className="relative font-serif flex items-center justify-center" style={innerStyle}>
                <span className={`text-5xl font-bold opacity-90 ${goldText}`}>H</span>
                <span className={`text-4xl absolute left-1/2 top-1/2 -translate-x-1/4 -translate-y-1/4 drop-shadow-md ${goldText}`}>م</span>
             </div>

             {/* Dynamic Light Reflection */}
             <div 
                className="absolute inset-0 opacity-30 bg-gradient-to-tr from-transparent via-white/20 to-transparent"
                style={{ transform: `translateX(${mousePos.x * 100}%) translateY(${mousePos.y * 100}%)`, transition: 'transform 0.2s ease-out' }}
             ></div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#080808] text-white font-sans overflow-hidden relative">

      {/* Ambient Lighting Blobs */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-[#BF953F]/10 blur-[120px] rounded-full animate-pulse"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-[#AA771C]/10 blur-[120px] rounded-full animate-pulse" style={{ animationDelay: '2s' }}></div>

      {/* Header */}
      <header className="border-b border-white/5 bg-[#0f0f0f]/80 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3 group cursor-pointer">
            <div className="w-10 h-10 rounded-full p-[1px]" style={{ background: 'linear-gradient(to bottom, #BF953F, #AA771C)' }}>
              <div className="w-full h-full rounded-full bg-[#1c1c1c] flex items-center justify-center">
                <span className={`font-serif text-[10px] ${goldText} font-bold`}>Hم</span>
              </div>
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight">هايبر المصري</h1>
              <p className={`text-[9px] uppercase tracking-[0.3em] font-bold ${goldText}`}>Hyper Al Masri</p>
            </div>
          </div>
          <nav className="hidden md:flex gap-8 text-[10px] uppercase tracking-[0.25em] text-gray-500 font-bold">
            {['exterior', 'packaging', 'uniform'].map((tab) => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`hover:text-[#FCF6BA] transition-all relative py-2 ${activeTab === tab ? 'text-[#D4AF37]' : ''}`}
              >
                {tab === 'exterior' ? 'الواجهة' : tab === 'packaging' ? 'التغليف' : 'الزي الموحد'}
                {activeTab === tab && <div className={`absolute bottom-0 left-0 w-full h-[1px] ${goldGradient}`}></div>}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6 py-12 relative z-10">

        {/* Section: Store Exterior */}
        {activeTab === 'exterior' && (
          <div className="space-y-16 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <div className="flex flex-col md:flex-row justify-between items-end gap-6">
              <div className="space-y-2">
                <div className="flex items-center gap-2">
                  <Sparkles size={14} className="text-[#BF953F]" />
                  <span className={`text-[10px] uppercase tracking-[0.4em] font-bold ${goldText}`}>The Gold Standard</span>
                </div>
                <h2 className="text-5xl font-serif">الواجهة الملكية</h2>
              </div>
              <p className="text-gray-500 max-w-sm text-right leading-relaxed italic border-r border-[#BF953F]/30 pr-4">
                "مزيج من الفخامة البصرية والتقنيات الحديثة، حيث يلتقي الرخام الأسود ببريق الذهب الحقيقي."
              </p>
            </div>

            {/* 3D TILT CARD */}
            <div 
              ref={cardRef}
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              className="relative aspect-video rounded-[3rem] overflow-hidden bg-[#111] border border-white/5 shadow-[0_40px_100px_rgba(0,0,0,0.8)] cursor-crosshair transition-transform duration-200 ease-out"
              style={{
                perspective: '1500px',
                transform: `rotateX(${mousePos.y * -10}deg) rotateY(${mousePos.x * 10}deg)`,
                transformStyle: 'preserve-3d'
              }}
            >
              {/* Facade Textures */}
              <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20"></div>
              <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-black/60"></div>

              {/* Store Signage with Depth */}
              <div className="absolute inset-0 flex flex-col items-center justify-center" style={{ transform: 'translateZ(60px)' }}>
                <div className="mb-8 drop-shadow-[0_20px_40px_rgba(0,0,0,0.5)]">
                   <LogoComponent size="lg" interactive={true} />
                </div>

                {/* Embossed Text Effect */}
                <div className="text-center space-y-4">
                  <h3 
                    className={`text-7xl md:text-9xl font-serif font-bold tracking-tighter filter drop-shadow-[0_5px_15px_rgba(0,0,0,0.8)] ${goldText}`}
                    style={{ textShadow: '0 10px 20px rgba(0,0,0,0.4)' }}
                  >
                    هايبر المصري
                  </h3>
                  <div className={`h-[2px] w-48 mx-auto ${goldGradient} shadow-lg shadow-[#BF953F]/20`}></div>
                  <p className="text-white/40 text-xl tracking-[0.6em] uppercase font-light translate-z-10">
                    Hyper Al Masri
                  </p>
                </div>
              </div>

              {/* Light Sweep Animation */}
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent -translate-x-full animate-[shimmer_5s_infinite] skew-x-12"></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {[
                { icon: <MapPin />, title: "التصميم المعماري", desc: "رخام إيطالي أسود مسقول بتشطيب 'High Gloss' يعكس الإضاءة." },
                { icon: <Award />, title: "التطعيم بالذهب", desc: "استخدام ورق الذهب عيار 24 في التفاصيل الدقيقة للوجو والزخارف." },
                { icon: <Store />, title: "الإضاءة الدرامية", desc: "توزيع إضاءة ذكي يبرز تباين الخامات بين المعتم واللامع." }
              ].map((item, i) => (
                <div key={i} className="group p-8 rounded-3xl bg-white/5 border border-white/10 hover:border-[#BF953F]/40 transition-all duration-500">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-6 bg-black border border-white/5 group-hover:scale-110 transition-transform ${goldText}`}>
                    {item.icon}
                  </div>
                  <h4 className="text-xl font-bold mb-3">{item.title}</h4>
                  <p className="text-sm text-gray-400 leading-relaxed">{item.desc}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Section: Packaging */}
        {activeTab === 'packaging' && (
          <div className="space-y-12 animate-in fade-in duration-700">
             <div className="flex flex-col md:flex-row justify-between items-end gap-6 border-b border-white/5 pb-8">
              <div className="space-y-2">
                <span className={`text-[10px] uppercase tracking-[0.4em] font-bold ${goldText}`}>The Unboxing Experience</span>
                <h2 className="text-4xl font-serif">فنون التغليف</h2>
              </div>
              <p className="text-gray-500 max-w-xs text-right text-sm">التغليف لدينا ليس مجرد حماية، بل هو أول لمسة تعكس الجودة الحقيقية.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
               {/* Premium Bag */}
               <div className="group relative aspect-square rounded-[3rem] bg-[#0d0d0d] border border-white/5 flex flex-col items-center justify-center p-12 overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-[6px] bg-gradient-to-r from-[#BF953F] via-[#FCF6BA] to-[#AA771C]"></div>

                  {/* The Bag Visualization */}
                  <div className="w-64 h-80 bg-[#121212] shadow-[0_30px_60px_rgba(0,0,0,0.5)] rounded-t-lg border border-white/5 relative transform group-hover:-translate-y-4 transition-transform duration-700">
                     <div className="absolute -top-10 left-1/2 -translate-x-1/2 flex gap-12">
                        <div className="w-1.5 h-16 bg-[#333] rounded-full group-hover:bg-[#BF953F] transition-colors"></div>
                        <div className="w-1.5 h-16 bg-[#333] rounded-full group-hover:bg-[#BF953F] transition-colors"></div>
                     </div>
                     <div className="h-full w-full flex flex-col items-center justify-center p-8">
                        <LogoComponent size="md" />
                        <h4 className={`text-2xl font-serif mt-6 ${goldText} font-bold`}>هايبر المصري</h4>
                        <div className="mt-4 w-12 h-[1px] bg-white/10"></div>
                        <p className="text-white/20 text-[7px] uppercase tracking-[0.5em] mt-4">Crafted Quality</p>
                     </div>
                  </div>
                  <div className="mt-8 text-sm font-bold tracking-widest text-gray-600 group-hover:text-[#BF953F] transition-colors">MATTE CHARCOAL & GOLD FOIL</div>
               </div>

               {/* Wheat Stalk Detail Section */}
               <div className="group relative aspect-square rounded-[3rem] bg-[#0d0d0d] border border-white/5 p-12 flex flex-col items-center justify-center">
                  <div className="text-[#BF953F] mb-8 group-hover:scale-110 transition-transform duration-700">
                    <svg width="100" height="140" viewBox="0 0 24 24" fill="none" stroke="url(#goldGradient)" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round">
                      <defs>
                        <linearGradient id="goldGradient" x1="0%" y1="0%" x2="0%" y2="100%">
                          <stop offset="0%" stopColor="#BF953F" />
                          <stop offset="50%" stopColor="#FCF6BA" />
                          <stop offset="100%" stopColor="#AA771C" />
                        </linearGradient>
                      </defs>
                      <path d="M12 2v20M12 6c-2 0-3-1-3-1s1 3 3 3 3-1 3-1-1 3-3 3M12 11c-2 0-3-1-3-1s1 3 3 3 3-1 3-1-1 3-3 3M12 16c-2 0-3-1-3-1s1 3 3 3 3-1 3-1-1 3-3 3" />
                    </svg>
                  </div>
                  <h4 className={`text-xl font-serif mb-4 ${goldText}`}>رمز السنبلة</h4>
                  <p className="text-gray-500 text-center text-sm leading-relaxed max-w-xs">
                    استخدام تدرجات المعدن في الرموز الدقيقة يعطي إحساساً بالنقاء والنمو المستمر.
                  </p>
               </div>
            </div>
          </div>
        )}

        {/* Section: Uniform */}
        {activeTab === 'uniform' && (
           <div className="space-y-12 animate-in fade-in duration-700">
             <div className="flex flex-col md:flex-row justify-between items-end gap-6 border-b border-white/5 pb-8">
              <div className="space-y-2">
                <span className={`text-[10px] uppercase tracking-[0.4em] font-bold ${goldText}`}>Brand Ambassadors</span>
                <h2 className="text-4xl font-serif">الزي الرسمي</h2>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
               {/* Polo Shirt */}
               <div className="p-12 rounded-[3rem] bg-[#0d0d0d] border border-white/5 flex flex-col items-center group">
                  <div className="w-full max-w-xs aspect-square bg-[#121212] rounded-full flex items-center justify-center mb-8 border border-white/10 relative overflow-hidden">
                     <div className="absolute inset-0 bg-gradient-to-br from-[#BF953F]/5 to-transparent"></div>
                     <div className="relative group-hover:scale-110 transition-transform duration-500">
                        <LogoComponent size="md" />
                        <div className="text-center mt-4">
                           <p className={`text-[10px] font-bold tracking-[0.4em] ${goldText}`}>TEAM CREW</p>
                        </div>
                     </div>
                  </div>
                  <h4 className="text-xl font-bold text-gray-300">تطريز ذهبي بارز</h4>
                  <p className="text-sm text-gray-500 mt-2 text-center max-w-xs">خيوط حريرية معالجة لتعكس الضوء كأنها سبائك ذهبية منسوجة.</p>
               </div>

               {/* Premium ID Card */}
               <div className="p-12 rounded-[3rem] bg-[#0d0d0d] border border-white/5 flex flex-col items-center group">
                  <div className="w-64 h-96 bg-[#121212] border border-white/10 rounded-2xl p-6 relative shadow-2xl overflow-hidden transform group-hover:rotate-1 transition-transform">
                     {/* Top Gold Bar */}
