{
  "name": "Hyper Al Masri - Luxury Retail Experience",
  "description": "A high-end luxury retail showcase featuring AI-powered concierge and design atelier."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export enum Tab {
  EXTERIOR = 'exterior',
  PACKAGING = 'packaging',
  UNIFORM = 'uniform',
  ATELIER = 'atelier'
}

export interface GeneratedImage {
  url: string;
  prompt: string;
}

import { GoogleGenAI } from "@google/genai";
import { ChatMessage } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const SYSTEM_INSTRUCTION = `
You are the "Royal Concierge" for Hyper Al Masri, an ultra-luxury retail brand inspired by modern Egyptian heritage, black marble, and pure gold. 
Your tone is sophisticated, elegant, polite, and slightly formal, befitting a high-end luxury service.
You assist customers with inquiries about our architectural grandeur, exquisite packaging, and staff attire.
Keep responses concise but evocative. Use words like "opulence", "craftsmanship", "heritage", and "timeless".
If asked about technical details (price, stock), politely suggest visiting our flagship boutique in Cairo.
`;

export const sendMessageToConcierge = async (
  history: ChatMessage[], 
  newMessage: string
): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';

    // Construct history for the stateless generateContent call or use chat session
    // For simplicity in this demo, we'll use a chat session structure
    const chat = ai.chats.create({
      model,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "I apologize, but I am currently attending to another guest. Please try again momentarily.";
  } catch (error) {
    console.error("Concierge Error:", error);
    return "My deepest apologies, there seems to be a disturbance in our communications.";
  }
};

export const generateLuxuryConcept = async (prompt: string): Promise<string | null> => {
  try {
    // We want to generate an image based on the user's prompt
    // First, let's refine the prompt to ensure it matches the brand aesthetic
    const refineModel = 'gemini-3-flash-preview';
    const refinementResponse = await ai.models.generateContent({
        model: refineModel,
        contents: `Refine the following prompt to create a high-end, photorealistic luxury product image description. 
        It should adhere to a style of "Black marble, gold accents, dramatic lighting, cinematic 8k".
        The user's input is: "${prompt}".
        Return ONLY the refined prompt text.`,
    });

    const refinedPrompt = refinementResponse.text || prompt;

    // Now generate the image
    const imageModel = 'gemini-2.5-flash-image';
    const response = await ai.models.generateContent({
      model: imageModel,
      contents: {
        parts: [
          { text: refinedPrompt }
        ]
      },
      config: {
        imageConfig: {
            aspectRatio: "1:1"
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Design Atelier Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Send, Sparkles, User, Gem } from 'lucide-react';
import { sendMessageToConcierge } from '../services/gemini';
import { ChatMessage } from '../types';

export const Concierge: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Welcome to the Hyper Al Masri Atelier. How may I assist you in your pursuit of excellence today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const responseText = await sendMessageToConcierge(messages, input);

    setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsLoading(false);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  // Gold text utility
  const goldText = "text-transparent bg-clip-text bg-gradient-to-b from-[#BF953F] via-[#FCF6BA] to-[#AA771C]";

  return (
    <div className="flex flex-col h-[600px] w-full max-w-4xl mx-auto bg-[#0d0d0d] rounded-[2rem] border border-white/10 overflow-hidden shadow-2xl relative">
       {/* Decorative Background */}
       <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-5 pointer-events-none"></div>

       {/* Header */}
       <div className="p-6 border-b border-white/5 bg-[#121212] flex items-center justify-between z-10">
          <div className="flex items-center gap-4">
             <div className="w-12 h-12 rounded-full p-[2px] bg-gradient-to-tr from-[#BF953F] to-[#AA771C]">
                <div className="w-full h-full rounded-full bg-black flex items-center justify-center">
                   <Gem size={20} className="text-[#FCF6BA]" />
                </div>
             </div>
             <div>
                <h3 className={`font-serif text-xl font-bold ${goldText}`}>The Royal Concierge</h3>
