              background: isGenerating || !prompt.trim() ? '' : 'linear-gradient(135deg, #BF953F 0%, #AA771C 100%)',
              color: isGenerating || !prompt.trim() ? '' : '#000'
            }}
          >
            {isGenerating ? (
              <>
                <Loader2 size={16} className="animate-spin" />
