عشان نعمل كدة، هنعدل كود صفحة `Marketplace.tsx` عشان بدل ما يجيب بيانات وهمية من `mockBackend`، يروح يجيب البيانات الحقيقية من `firebase`.

**خدي الكود ده انسخيه كله وحطيه مكان الكود اللي في ملف `components/Marketplace.tsx`:**

```typescript
import React, { useState, useEffect } from 'react';
import { Search, Plus, ShoppingBag, Star, Filter } from 'lucide-react';
import { Product, CartItem } from '../types';
// import { searchProducts } from '../services/mockBackend'; <-- شيلنا السطر ده خلاص
import { db } from '../services/firebase'; // ضيفنا ده عشان نكلم الداتابيز
import { collection, getDocs } from 'firebase/firestore'; // أدوات جلب البيانات

interface MarketplaceProps {
  cart: CartItem[];
  addToCart: (product: Product) => void;
}

// Configuration for Category Colors
const CATEGORY_STYLES: Record<string, { bg: string, text: string, border: string, iconColor: string }> = {
  'خضروات وفواكه': { bg: 'bg-[#6AA84F]/10', text: 'text-[#6AA84F]', border: 'border-[#6AA84F]/30', iconColor: '#6AA84F' },
  'لحوم ومجمدات': { bg: 'bg-[#2E86AB]/10', text: 'text-[#5DADE2]', border: 'border-[#2E86AB]/30', iconColor: '#5DADE2' },
  'بقالة ومؤن': { bg: 'bg-[#BF953F]/10', text: 'text-[#BF953F]', border: 'border-[#BF953F]/30', iconColor: '#BF953F' },
  'عطارة': { bg: 'bg-[#D35400]/10', text: 'text-[#E59866]', border: 'border-[#D35400]/30', iconColor: '#E59866' },
  'All': { bg: 'bg-white/5', text: 'text-gray-400', border: 'border-white/10', iconColor: '#999' }
};

export const Marketplace: React.FC<MarketplaceProps> = ({ cart, addToCart }) => {
  const [query, setQuery] = useState('');
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('All');

  const goldText = "text-transparent bg-clip-text bg-gradient-to-b from-[#BF953F] via-[#FCF6BA] to-[#AA771C]";

  // ده الكود الجديد اللي بيروح يجيب المنتجات من المخزن الحقيقي
  useEffect(() => {
    const fetch = async () => {
      setIsLoading(true);
      try {
        // 1. بنروح للمخزن (collection called 'products')
        const querySnapshot = await getDocs(collection(db, "products"));

        // 2. بنحول البيانات لشكل يفهمه الموقع
        let realProducts = querySnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
          // بنحط قيم افتراضية لو فيه حقل ناقص عشان الموقع ميضربش
          rating: doc.data().rating || 4.8, 
          description: doc.data().description || "منتج طازج وعالي الجودة من هايبر المصري",
          image: doc.data().image || "https://placehold.co/400x300?text=No+Image"
        })) as Product[];

        // 3. لو المستخدم كتب حاجة في البحث، بنفلتر النتائج
        if (query) {
          realProducts = realProducts.filter(p => 
            p.name.includes(query) || (p.description && p.description.includes(query))
          );
        }

        setProducts(realProducts);
      } catch (error) {
        console.error("Error fetching products:", error);
      }
      setIsLoading(false);
    };

    // Debounce simulation (عشان ميعملش بحث مع كل حرف بسرعة)
    const timeoutId = setTimeout(fetch, 300);
    return () => clearTimeout(timeoutId);
  }, [query]); // بيعيد التشغيل لما تكتبي في البحث

  const categories = ['All', 'خضروات وفواكه', 'لحوم ومجمدات', 'بقالة ومؤن', 'عطارة'];

  const filteredProducts = selectedCategory === 'All' 
    ? products 
    : products.filter(p => p.category === selectedCategory);

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex flex-col md:flex-row justify-between items-end gap-6 border-b border-white/5 pb-8">
        <div className="space-y-2">
          <div className="flex items-center gap-2">
            <ShoppingBag size={14} className="text-[#BF953F]" />
            <span className={`text-[10px] uppercase tracking-[0.4em] font-bold ${goldText}`}>السوق اليومي</span>
          </div>
          <h2 className="text-4xl font-serif">تسوق طلبات بيتك</h2>
        </div>

        {/* Search Bar */}
        <div className="relative w-full md:w-96 group">
            <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                <Search size={16} className="text-gray-500 group-focus-within:text-[#BF953F] transition-colors" />
            </div>
            <input
                type="text"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-[#1a1a1a] border border-white/10 rounded-xl py-3 pr-10 pl-4 text-sm focus:outline-none focus:border-[#BF953F]/50 transition-all text-white placeholder-gray-500 focus:shadow-[0_0_15px_rgba(191,149,63,0.1)] text-right"
                placeholder="ابحث عن منتج (أرز، سكر، لحوم...)"
                dir="rtl"
            />
        </div>
      </div>

